// Verarbeite Zauber und Liturgien mit HTML-Inhalten
// Process spells and liturgies with HTML content

if (!game.sephrasto) {
    ui.notifications.error('SephrastoImporter ist nicht verfügbar. Das System muss möglicherweise neu geladen werden.');
} else {
    ui.notifications.info('Beginne mit der Verarbeitung von Zauber-HTML-Inhalten...');

    game.sephrasto.processSpellsWithHtmlContent().then(count => {
        if (count > 0) {
            ui.notifications.info(`Verarbeitung abgeschlossen. ${count} Zauber/Liturgien wurden aktualisiert.`);
        } else {
            ui.notifications.info('Keine Zauber mit HTML-Inhalten gefunden, die verarbeitet werden müssen.');
        }
    }).catch(error => {
        console.error('Fehler bei der HTML-Verarbeitung:', error);
        ui.notifications.error('Fehler bei der Verarbeitung der Zauber-HTML-Inhalte. Siehe Konsole für Details.');
    });
}
